import{_ as t,o as a,c as n,a2 as s}from"./chunks/framework.u8r3paJC.js";const u=JSON.parse('{"title":"Architecture Decision Records","description":"","frontmatter":{},"headers":[],"relativePath":"adr/index.md","filePath":"adr/index.md"}'),r={name:"adr/index.md"};function i(o,e,d,c,l,h){return a(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="architecture-decision-records" tabindex="-1">Architecture Decision Records <a class="header-anchor" href="#architecture-decision-records" aria-label="Permalink to &quot;Architecture Decision Records&quot;">​</a></h1><p>These records document every significant architectural decision made during BlockBite&#39;s development. Each ADR captures the <strong>context</strong>, <strong>alternatives considered</strong>, <strong>decision taken</strong>, and <strong>consequences</strong> — so future contributors understand not just <em>what</em> was built, but <em>why</em>.</p><table tabindex="0"><thead><tr><th>#</th><th>Title</th><th>Status</th><th>Date</th></tr></thead><tbody><tr><td>ADR-001</td><td><a href="#adr-001-separate-_dispatchrs-for-anchor-boilerplate">Separate <code>_dispatch.rs</code> for Anchor Boilerplate</a></td><td>Accepted</td><td>2026-01 Week 4</td></tr><tr><td>ADR-002</td><td><a href="#adr-002-cei-checks-effects-interactions-pattern-on-every-instruction">CEI Pattern on Every Instruction</a></td><td>Accepted</td><td>2026-01 Week 4</td></tr><tr><td>ADR-003</td><td><a href="#adr-003-game_authority-as-on-chain-oracle-for-milestone-verification"><code>game_authority</code> as On-Chain Oracle</a></td><td>Accepted</td><td>2026-02 Week 5</td></tr><tr><td>ADR-004</td><td><a href="#adr-004-dual-pda-architecture-stream--escrow-as-separate-accounts">Dual PDA Architecture</a></td><td>Accepted</td><td>2026-01 Week 4</td></tr><tr><td>ADR-005</td><td><a href="#adr-005-title_hash--description_hash-as-32-byte-on-chain-commitments">32-byte On-Chain Content Hashes</a></td><td>Accepted</td><td>2026-02 Week 5</td></tr><tr><td>ADR-006</td><td><a href="#adr-006-creator-controlled-milestone-gate-on-stream-vesting">Creator-Controlled Milestone Gate</a></td><td>Accepted</td><td>2026-02 Week 5</td></tr></tbody></table><hr><h2 id="adr-001-separate-dispatch-rs-for-anchor-boilerplate" tabindex="-1">ADR-001: Separate <code>_dispatch.rs</code> for Anchor Boilerplate <a class="header-anchor" href="#adr-001-separate-dispatch-rs-for-anchor-boilerplate" aria-label="Permalink to &quot;ADR-001: Separate `_dispatch.rs` for Anchor Boilerplate&quot;">​</a></h2><p><strong>Status:</strong> Accepted · <strong>Date:</strong> 2026-01 (Week 4)</p><h3 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>Anchor&#39;s <code>#[derive(Accounts)]</code> structs and public instruction handlers require a running BPF runtime to execute — they cannot be reached by <code>cargo test</code> without a live validator. But the business logic inside each instruction (timestamp math, unlock calculations, cancel splits) is pure Rust, fully testable without any on-chain infrastructure.</p><p>Mixing both in the same file makes unit testing impossible and produces noisy code coverage numbers.</p><h3 id="alternatives-considered" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Reason rejected</th></tr></thead><tbody><tr><td>Everything in <code>lib.rs</code></td><td>Bloats entrypoint; unit tests can&#39;t import instruction logic directly</td></tr><tr><td>One file per instruction, no separation</td><td>Anchor boilerplate and business logic remain coupled; <code>cargo test</code> fails with BPF errors</td></tr><tr><td><strong>Separate dispatch + pure logic files</strong> ✅</td><td>Chosen — clean, testable, accurate coverage</td></tr></tbody></table><h3 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p>All Anchor boilerplate (<code>#[derive(Accounts)]</code> + thin handler wrappers) lives in <code>src/instructions/_dispatch.rs</code>. Business logic lives in per-instruction pure-function files (<code>init_stream</code>, <code>compute_withdraw</code>, <code>compute_cancel</code>, etc.). Coverage excludes <code>_dispatch.rs</code> via <code>--ignore-filename-regex</code>.</p><h3 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>✅ Unit tests import pure functions directly — fast, offline, deterministic<br> ✅ Code coverage reflects actual business logic, not macro scaffolding<br> ✅ Each instruction file is small and focused<br> ⚠️ New instructions require changes in two files — the pure logic file and <code>_dispatch.rs</code></p><hr><h2 id="adr-002-cei-checks-effects-interactions-pattern-on-every-instruction" tabindex="-1">ADR-002: CEI (Checks-Effects-Interactions) Pattern on Every Instruction <a class="header-anchor" href="#adr-002-cei-checks-effects-interactions-pattern-on-every-instruction" aria-label="Permalink to &quot;ADR-002: CEI (Checks-Effects-Interactions) Pattern on Every Instruction&quot;">​</a></h2><p><strong>Status:</strong> Accepted · <strong>Date:</strong> 2026-01 (Week 4)</p><h3 id="context-1" tabindex="-1">Context <a class="header-anchor" href="#context-1" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>Solana programs call other programs via CPI. If state is mutated <em>after</em> a CPI, a malicious re-entrant program could exploit the window between CPI and state update. Rust&#39;s borrow checker catches data-race bugs within a single transaction but cannot detect logical reentrancy across CPI boundaries.</p><p>BlockBite has four instructions (<code>withdraw</code>, <code>cancel</code>, <code>claim_milestone</code>, <code>close_stream</code>) that mutate state AND transfer tokens.</p><h3 id="alternatives-considered-1" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered-1" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Reason rejected</th></tr></thead><tbody><tr><td>No explicit ordering discipline</td><td>Acceptable only for single-CPI instructions with no shared mutable state; risky with <code>cancel</code> (two CPIs)</td></tr><tr><td>On-account reentrancy lock flag</td><td>Extra storage overhead; no native Solana mutex primitive</td></tr><tr><td><strong>CEI ordering enforced by pure-function architecture</strong> ✅</td><td>Zero runtime overhead; naturally enforced by ADR-001&#39;s design</td></tr></tbody></table><h3 id="decision-1" tabindex="-1">Decision <a class="header-anchor" href="#decision-1" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p>Every mutating instruction follows strict CEI order:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Checks     — all require! validations (read-only, fail-fast)</span></span>\n<span class="line"><span>2. Effects    — all state mutations (is_cancelled, amount_withdrawn, is_claimed)</span></span>\n<span class="line"><span>3. Interactions — all CPI token transfers</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>The pure-function architecture from ADR-001 enforces this naturally: <code>compute_withdraw</code> mutates state and returns the transfer amount; the mutable borrow drops; then the handler calls the CPI.</p><p><strong>Concrete example — <code>claim_milestone</code>:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CHECK:    is_verified == true, !is_claimed, recipient == signer</span></span>\n<span class="line"><span>EFFECT:   milestone.is_claimed = true           ← before CPI</span></span>\n<span class="line"><span>INTERACT: transfer token_amount → recipient ATA ← after state</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="consequences-1" tabindex="-1">Consequences <a class="header-anchor" href="#consequences-1" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>✅ Eliminates reentrancy risk on all instructions<br> ✅ CEI order is visible and reviewable at the handler level<br> ✅ Passed the Week 7 security audit<br> ⚠️ Requires discipline on new instructions — explicit variable extraction after borrow drop adds a few lines</p><hr><h2 id="adr-003-game-authority-as-on-chain-oracle-for-milestone-verification" tabindex="-1">ADR-003: <code>game_authority</code> as On-Chain Oracle for Milestone Verification <a class="header-anchor" href="#adr-003-game-authority-as-on-chain-oracle-for-milestone-verification" aria-label="Permalink to &quot;ADR-003: `game_authority` as On-Chain Oracle for Milestone Verification&quot;">​</a></h2><p><strong>Status:</strong> Accepted · <strong>Date:</strong> 2026-02 (Week 5)</p><h3 id="context-2" tabindex="-1">Context <a class="header-anchor" href="#context-2" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>The game reward system needs an answer to: <em>&quot;did this player actually reach the target level?&quot;</em> Without a verifiable signal, players can self-report false achievements.</p><h3 id="alternatives-considered-2" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered-2" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Reason rejected</th></tr></thead><tbody><tr><td>Trust the player (self-report)</td><td>Trivially gameable — no security</td></tr><tr><td>Founder manually verifies</td><td>Founder becomes a bottleneck and single trust point; doesn&#39;t scale</td></tr><tr><td><strong>Designated game-server keypair</strong> ✅</td><td>Chosen — lightweight oracle, no third-party dependency</td></tr><tr><td>ZK proof</td><td>Ideal but requires custom circuits; not feasible in hackathon scope</td></tr><tr><td>Switchboard / Pyth oracle</td><td>General-purpose oracle; overkill for bespoke game events; adds protocol dependency</td></tr></tbody></table><h3 id="decision-2" tabindex="-1">Decision <a class="header-anchor" href="#decision-2" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p>Each <code>MilestoneAccount</code> stores a <code>game_authority: Pubkey</code> set at creation time. Only a transaction signed by that keypair can call <code>verify_game</code>. The game server backend monitors player progress and submits <code>verify_game</code> when the target is reached.</p><p>Per-milestone authority means different game integrations or seasons can use different signing keys — blast radius of a compromised key is limited to its milestones.</p><h3 id="consequences-2" tabindex="-1">Consequences <a class="header-anchor" href="#consequences-2" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>✅ Trustless from the player&#39;s perspective — they cannot fake verification<br> ✅ No ZK complexity; deployed and running on Solana Devnet today<br> ✅ Per-milestone authority limits key-compromise blast radius<br> ✅ Cheap: one extra <code>Pubkey</code> (32 bytes) per <code>MilestoneAccount</code><br> ⚠️ Game server is a trusted party — offline server = blocked verifications<br> ⚠️ No slashing if game server lies — mitigated by publisher reputation risk<br> ⚠️ Key rotation requires new milestone accounts (no update path)</p><p><strong>Future improvement:</strong> Replace the single hot-wallet key with a Squads multisig or Switchboard oracle for production.</p><hr><h2 id="adr-004-dual-pda-architecture-stream-escrow-as-separate-accounts" tabindex="-1">ADR-004: Dual PDA Architecture (Stream + Escrow as Separate Accounts) <a class="header-anchor" href="#adr-004-dual-pda-architecture-stream-escrow-as-separate-accounts" aria-label="Permalink to &quot;ADR-004: Dual PDA Architecture (Stream + Escrow as Separate Accounts)&quot;">​</a></h2><p><strong>Status:</strong> Accepted · <strong>Date:</strong> 2026-01 (Week 4)</p><h3 id="context-3" tabindex="-1">Context <a class="header-anchor" href="#context-3" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>Vested tokens must be held by the program so it can transfer them autonomously. The question is where the SPL tokens should live.</p><h3 id="alternatives-considered-3" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered-3" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Reason rejected</th></tr></thead><tbody><tr><td>Single PDA with SOL balance</td><td>Only works for SOL, not SPL tokens</td></tr><tr><td>Creator-owned escrow (ATA)</td><td>Creator retains custody — fully gameable</td></tr><tr><td><strong>Dual PDA</strong> ✅</td><td>Chosen — <code>StreamAccount</code> holds metadata; <code>EscrowTokenAccount</code> (authority = stream PDA) holds tokens</td></tr></tbody></table><h3 id="decision-3" tabindex="-1">Decision <a class="header-anchor" href="#decision-3" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p><code>StreamAccount</code> (seeds: <code>[&quot;stream&quot;, creator, recipient, seed]</code>) + <code>EscrowTokenAccount</code> (seeds: <code>[&quot;escrow&quot;, stream_pubkey]</code>). The escrow&#39;s SPL token authority is set to the <code>StreamAccount</code> PDA, so only the program can move tokens via <code>CpiContext::new_with_signer</code>.</p><p>Escrow derived from stream means it is uniquely discoverable from just the stream PDA — no extra storage or lookup table needed.</p><h3 id="consequences-3" tabindex="-1">Consequences <a class="header-anchor" href="#consequences-3" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>✅ Works with any SPL token mint<br> ✅ Clean separation: state vs funds in separate accounts<br> ✅ Escrow uniquely discoverable from stream PDA<br> ✅ <code>close_stream</code> atomically closes both accounts, returning all rent<br> ✅ Anchor&#39;s <code>token::authority</code> constraint enforces escrow ownership at compile time<br> ⚠️ Two accounts to derive and pass per instruction (slightly higher tx overhead)<br> ⚠️ Higher creation cost: ~0.004 SOL rent for two <code>init</code> accounts (recovered on <code>close_stream</code>)</p><hr><h2 id="adr-005-title-hash-description-hash-as-32-byte-on-chain-commitments" tabindex="-1">ADR-005: <code>title_hash</code> / <code>description_hash</code> as 32-byte On-Chain Commitments <a class="header-anchor" href="#adr-005-title-hash-description-hash-as-32-byte-on-chain-commitments" aria-label="Permalink to &quot;ADR-005: `title_hash` / `description_hash` as 32-byte On-Chain Commitments&quot;">​</a></h2><p><strong>Status:</strong> Accepted · <strong>Date:</strong> 2026-02 (Week 5)</p><h3 id="context-4" tabindex="-1">Context <a class="header-anchor" href="#context-4" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>Campaign titles and milestone descriptions are arbitrary-length strings. Storing them on-chain costs lamports proportional to byte length. Storing nothing on-chain breaks tamper-evidence — a founder could silently change terms after players sign up.</p><h3 id="alternatives-considered-4" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered-4" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Reason rejected</th></tr></thead><tbody><tr><td>Store full strings on-chain</td><td>Expensive; hits account size limits; can&#39;t be updated</td></tr><tr><td>Store nothing</td><td>No accountability; off-chain content can be changed unilaterally</td></tr><tr><td><strong>32-byte SHA-256 hash</strong> ✅</td><td>Fixed cost, tamper-evident, IPFS-compatible</td></tr><tr><td>IPFS CID as string</td><td>46+ bytes as base58 — same content in raw multihash fits in 32 bytes</td></tr></tbody></table><h3 id="decision-4" tabindex="-1">Decision <a class="header-anchor" href="#decision-4" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p>Store a 32-byte SHA-256 (or IPFS CID multihash) of the content on-chain. Full text lives off-chain (IPFS/Arweave/backend DB). Any party can verify authenticity by hashing the off-chain content and comparing:</p><div class="language-typescript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { createHash } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;crypto&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> hash</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    =</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Array.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">createHash</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;sha256&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(offChainTitle).</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">digest</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">());</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> matches</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(hash) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> JSON</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">stringify</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(Array.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(campaign.titleHash));</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="consequences-4" tabindex="-1">Consequences <a class="header-anchor" href="#consequences-4" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>✅ Fixed 32-byte on-chain cost regardless of content length<br> ✅ Tamper-evident — altered off-chain content produces a different hash<br> ✅ Compatible with SHA-256 and IPFS CIDv1 multihashes<br> ⚠️ Off-chain content availability not guaranteed — mitigated by IPFS pinning<br> ⚠️ Hash scheme is by convention (SHA-256) — not encoded in the account structure<br> ⚠️ Hash cannot be updated after account creation</p><hr><h2 id="adr-006-creator-controlled-milestone-gate-on-stream-vesting" tabindex="-1">ADR-006: Creator-Controlled Milestone Gate on Stream Vesting <a class="header-anchor" href="#adr-006-creator-controlled-milestone-gate-on-stream-vesting" aria-label="Permalink to &quot;ADR-006: Creator-Controlled Milestone Gate on Stream Vesting&quot;">​</a></h2><p><strong>Status:</strong> Accepted · <strong>Date:</strong> 2026-02 (Week 5)</p><h3 id="context-5" tabindex="-1">Context <a class="header-anchor" href="#context-5" aria-label="Permalink to &quot;Context&quot;">​</a></h3><p>Standard token vesting is purely time-based. Many real vesting agreements attach performance conditions: &quot;team tokens unlock only after mainnet launch&quot; or &quot;investor tokens unlock after reaching 10 000 users.&quot; These events are binary but subjective — they can&#39;t be fed directly from an oracle.</p><h3 id="alternatives-considered-5" tabindex="-1">Alternatives Considered <a class="header-anchor" href="#alternatives-considered-5" aria-label="Permalink to &quot;Alternatives Considered&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Reason rejected</th></tr></thead><tbody><tr><td>Time-only vesting</td><td>Already handled by <code>cliff_time</code> + <code>end_time</code>; doesn&#39;t cover event-based gates</td></tr><tr><td>On-chain oracle gate (Pyth/Switchboard)</td><td>Would need the oracle to publish exactly the right metric feed for arbitrary KPIs</td></tr><tr><td>Multisig approval</td><td>Governance overhead; overkill for a two-party vesting agreement</td></tr><tr><td><strong>Creator-controlled boolean gate</strong> ✅</td><td>Chosen — simple, flexible, covers any off-chain event parties agree on</td></tr></tbody></table><h3 id="decision-5" tabindex="-1">Decision <a class="header-anchor" href="#decision-5" aria-label="Permalink to &quot;Decision&quot;">​</a></h3><p><code>StreamAccount</code> has two fields: <code>milestone_enabled: bool</code> (set at creation, immutable) and <code>milestone_reached: bool</code> (creator-only, one-way flip via <code>set_milestone</code>). When <code>milestone_enabled</code> is <code>true</code>, <code>calculate_unlocked</code> returns 0 until <code>milestone_reached</code> is also <code>true</code> — regardless of elapsed time.</p><p>This gate composes with <code>cliff_time</code> — four distinct vesting modes from two boolean flags:</p><table tabindex="0"><thead><tr><th><code>cliff_time</code></th><th><code>milestone_enabled</code></th><th>Mode</th></tr></thead><tbody><tr><td><code>0</code></td><td><code>false</code></td><td>Pure linear</td></tr><tr><td><code>&gt; 0</code></td><td><code>false</code></td><td>Cliff + linear</td></tr><tr><td><code>0</code></td><td><code>true</code></td><td>Milestone gate + linear</td></tr><tr><td><code>&gt; 0</code></td><td><code>true</code></td><td>Cliff AND milestone gate + linear</td></tr></tbody></table><h3 id="consequences-5" tabindex="-1">Consequences <a class="header-anchor" href="#consequences-5" aria-label="Permalink to &quot;Consequences&quot;">​</a></h3><p>✅ Zero oracle dependency — any off-chain event can trigger the gate<br> ✅ Single low-cost instruction (<code>set_milestone</code>) — no governance ceremony<br> ✅ Composable with cliff/linear vesting<br> ✅ Recipient is cryptographically protected — creator can only flip the gate or cancel (which pays vested portion to recipient)<br> ⚠️ Creator is the trusted party for the milestone decision — no on-chain dispute resolution<br> ⚠️ Gate is one-way — once set, it cannot be unset (intentional; protects the recipient)<br> ⚠️ No on-chain deadline for when creator must call <code>set_milestone</code> — include a fallback time in the off-chain agreement</p>',81)])])}const b=t(r,[["render",i]]);export{u as __pageData,b as default};
